<?php
namespace App\Controllers;
use App\Core\{Database,Request,Response}; use App\Middlewares\AuthMiddleware;
final class PixController {
  public static function saveKey(): void { $id=AuthMiddleware::userId(); $b=Request::body(); if(empty($b['key_type'])||empty($b['pix_key'])) Response::json(['error'=>'Informe tipo e chave Pix'],422); $st=Database::connection()->prepare('INSERT INTO pix_keys(user_id,key_type,pix_key,holder_name,active,created_at,updated_at) VALUES(?,?,?,?,1,NOW(),NOW()) ON DUPLICATE KEY UPDATE key_type=VALUES(key_type), pix_key=VALUES(pix_key), holder_name=VALUES(holder_name), active=1, updated_at=NOW()'); $st->execute([$id,$b['key_type'],$b['pix_key'],$b['holder_name']??null]); Response::json(['message'=>'Chave Pix cadastrada']); }
  public static function myKey(): void { $id=AuthMiddleware::userId(); $st=Database::connection()->prepare('SELECT id,key_type,pix_key,holder_name,active FROM pix_keys WHERE user_id=? AND active=1 LIMIT 1');$st->execute([$id]); Response::json($st->fetch()?:null); }
  public static function gift(array $p): void { $sender=AuthMiddleware::userId(); $bookId=(int)$p['bookId']; $recipient=(int)(Request::body()['recipient_id']??0); $amount=(float)(Request::body()['amount']??0); if($recipient<=0||$amount<=0) Response::json(['error'=>'Informe destinatário e valor'],422); $pdo=Database::connection(); $key=$pdo->prepare('SELECT * FROM pix_keys WHERE user_id=? AND active=1');$key->execute([$recipient]); $pix=$key->fetch(); if(!$pix) Response::json(['error'=>'Usuário ainda não cadastrou chave Pix'],422); $st=$pdo->prepare('INSERT INTO gift_payments(sender_id,recipient_id,book_id,amount,status,pix_key_snapshot,created_at,updated_at) VALUES(?,?,?,?,"PENDING",?,NOW(),NOW())'); $st->execute([$sender,$recipient,$bookId,$amount,$pix['pix_key']]); Response::json(['message'=>'Pedido de presente criado','payment_id'=>$pdo->lastInsertId(),'pix'=>['key_type'=>$pix['key_type'],'pix_key'=>$pix['pix_key'],'amount'=>$amount,'provider'=>$_ENV['PIX_PROVIDER']??'internal']]); }
}
